  1	import * as React from 'react';
  2	import {
  3	  BucketVersioningStatus,
  4	  GetBucketVersioningCommandOutput,
  5	} from '@aws-sdk/client-s3';
  6	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
  7	import { CommonModalProps } from '@odf/shared/modals';
  8	import { S3Commands } from '@odf/shared/s3';
  9	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 10	import { KeyedMutator } from 'swr';
 11	import {
 12	  Modal,
 13	  ModalVariant,
 14	  Button,
 15	  ButtonVariant,
 16	} from '@patternfly/react-core';
 17	
 18	export type SetVersioningModalModalProps = {
 19	  mutate: KeyedMutator<GetBucketVersioningCommandOutput>;
 20	  s3Client: S3Commands;
 21	  bucketName: string;
 22	  enableVersioning: boolean;
 23	};
 24	
 25	const SetVersioningModal: React.FC<
 26	  CommonModalProps<SetVersioningModalModalProps>
 27	> = ({
 28	  closeModal,
 29	  isOpen,
 30	  extraProps: { s3Client, bucketName, mutate, enableVersioning },
 31	}) => {
 32	  const { t } = useCustomTranslation();
 33	
 34	  const [inProgress, setInProgress] = React.useState<boolean>(false);
 35	  const [error, setError] = React.useState<Error>();
 36	
 37	  const onEnableOrSuspend = async () => {
 38	    setInProgress(true);
 39	
 40	    try {
 41	      const params = {
 42	        Bucket: bucketName,
 43	        VersioningConfiguration: {
 44	          Status: enableVersioning
 45	            ? BucketVersioningStatus.Enabled
 46	            : BucketVersioningStatus.Suspended,
 47	        },
 48	      };
 49	      await s3Client.putBucketVersioning(params);
 50	
 51	      mutate();
 52	      setInProgress(false);
 53	      closeModal();
 54	    } catch (err) {
 55	      setError(err);
 56	      setInProgress(false);
 57	    }
 58	  };
 59	
 60	  return (
 61	    <Modal
 62	      title={
 63	        enableVersioning ? t('Enable Versioning') : t('Suspend versioning')
 64	      }
 65	      titleIconVariant="warning"
 66	      isOpen={isOpen}
 67	      onClose={closeModal}
 68	      description={
 69	        <div className="text-muted">
 70	          {enableVersioning
 71	            ? t(
 72	                'Enable versioning may lead to increased expenses. You will need to update the lifecycle rules after enabling versions.'
 73	              )
 74	            : t(
 75	                'Preserves any previous object versions. Changes will be applied to newly created objects.'
 76	              )}
 77	        </div>
 78	      }
 79	      variant={ModalVariant.medium}
 80	      actions={[
 81	        <ButtonBar
 82	          inProgress={inProgress}
 83	          errorMessage={error?.message || JSON.stringify(error)}
 84	        >
 85	          <span>
 86	            <Button
 87	              variant={ButtonVariant.primary}
 88	              onClick={onEnableOrSuspend}
 89	              isDisabled={!!error || inProgress}
 90	              className="pf-v6-u-mr-xs"
 91	            >
 92	              {enableVersioning ? t('Enable') : t('Suspend')}
 93	            </Button>
 94	            <Button
 95	              variant={ButtonVariant.link}
 96	              onClick={closeModal}
 97	              className="pf-v6-u-ml-xs"
 98	            >
 99	              {t('Cancel')}
100	            </Button>
101	          </span>
102	        </ButtonBar>,
103	      ]}
104	    >
105	      {' '}
106	    </Modal>
107	  );
108	};
109	
110	export default SetVersioningModal;

